def partition_even_odd(numbers):
    evens = [n for n in numbers if n % 2 == 0]
    odds = [n for n in numbers if n % 2 != 0]
    return (evens, odds)

def compress_runs(items):
    if not items:
        return []
    result = [items[0]]
    for item in items[1:]:
        if item != result[-1]:
            result.append(item)
    return result

def index_by_id(records):
    result = {}
    for record in records:
        result[record['id']] = record
    return result

def diagonal_sum(matrix):
    if not matrix:
        return 0
    total = 0
    for i in range(len(matrix)):
        total += matrix[i][i]
    return total

def take_until(items, stop_value):
    result = []
    for item in items:
        if item == stop_value:
            break
        result.append(item)
    return result
